   '[{"id":"block-c559d339-0d39-4c9f-8236-c25e28fbdee3","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776240170934_ljrwi0pd8i.png","imageSize":260},{"id":"block-cd6f2809-4107-426b-b8fa-cbcaab510c2b","type":"text","value":"Additional components needed: two d6''s, a pawn & a pencil","blockWidth":"full"},{"id":"block-e1f78d67-606a-4bd0-b5c2-e20d019e3ee2","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776240300627_lzt8fwpeqbi.png","imageFit":"cover","imageSize":140,"blockWidth":"full","imagePosition":{"x":52,"y":25},"verticalAlign":"top"},{"id":"block-a3af0723-7984-47d4-81d0-9ba1c1c4277e","type":"text","value":"Place the pawn on the image of the messenger at the top of the hex map. Keep the dice and pencil nearby.","blockWidth":"full"},{"id":"block-34f164ff-0de2-4b5d-8e90-d40578354fac","type":"section","value":"How to Play"},{"id":"block-5e35ec2e-b0ee-4d3b-8ce9-da9ad828d1ec","type":"steps","value":"Roll both dice, apply any desired effects if any abilities have been unlocked\nIf a 5 is rolled, cross out one heart (health)\nIf a 6 is rolled, fill in the topmost empty circle of the Time track\nThen, spend each die (by moving it away from the play area) on one of the following:\n\tMove pawn to an adjacent space that corresponds with die # (Not Mountain spaces, unless ability unlocked)\n\tCross off a requirement for an ability\nGrab the dice and repeat steps 1-4 until you reach the Queen in the Castle (key is required) and win!","blockFormat":"steps"},{"id":"block-20fe2ade-6492-404a-b0a5-9b2784b199b4","type":"callout","value":"If a 5 is rolled, cross out one heart (health)","variant":"warning"},{"id":"block-cc89b176-4949-4c00-8818-16a0e2dd1d18","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242125423_z1jb2hs03qe.png","imageSize":240},{"id":"block-d96bc7ac-8a38-4ba5-8e6b-47916323e4c0","type":"callout","value":"If a 6 is rolled, fill in the topmost empty circle of the time track","variant":"info"},{"id":"block-d1cd19d9-627f-41b8-836c-050047a81ccc","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776270106093_ntdc4c8ur2e.png","imageSize":390},{"id":"block-69df2aed-72d0-4fb7-bd16-3fd70516508d","type":"section","value":"Winning and Losing"},{"id":"block-ae55781d-a30a-4f17-9411-fdc0212aa24d","type":"text","value":"Win by reaching the Queen in the Castle (key is required)."},{"id":"block-93d3417e-bf94-4c5f-a96f-7187caaf91e5","type":"text","value":"You lose if: you haven''t moved into a region before its topmost Time space is filled in OR you lose all health"},{"id":"block-d06ed0e6-ab6d-42c7-bb8d-6e72b8092a85","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242246552_3fnqag8qxg2.png","imageSize":330},{"id":"block-9217e3d0-7c2a-40c2-9beb-2d7eaeeb9981","type":"section","value":"Regions and Time"},{"id":"block-f544c2fa-d1f1-4c65-9225-a02d857611c5","type":"text","value":"There are six regions behind the map. You need to enter a region before its topmost Time space is filled."},{"id":"block-6f14304b-fecf-4368-a7c3-191943890b7f","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242291492_z4690hu8t5.png","imageFit":"contain"},{"id":"block-8fcf17e1-6c33-496a-b3d7-99edf48aaacb","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242307466_9qqa9sizlc4.png","imageFit":"contain"},{"id":"block-e884bcf2-796f-422b-9469-461aa2b630e1","type":"text","value":"If a 6 is rolled, fill in the topmost empty circle of the Time track."},{"id":"block-e74b6221-d5bc-4c48-8ba6-1159e4f57cc2","type":"section","value":"Abilities"},{"id":"block-e3347843-9c0b-486c-b116-8771234c2c5d","type":"text","value":"The available abilities are all below the hex map. Check the box next to an ability once all requirements have been met. That ability is now available for the rest of the game."},{"id":"block-b8a46686-f015-4059-ab9c-b068bd7fb4dc","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242334767_luwfgkf5zuh.png","imageSize":340},{"id":"block-2b295664-a1e4-4929-879f-334b121a9190","type":"section","value":"Change a die +/- 1 (once per turn)"},{"id":"block-1ca2aec0-f84d-4b28-94e0-c30f777916f6","type":"text","value":"Any die can be spent to draw a circle in this area. This circle can then be filled in to change a die up or down by 1. Note: 6''s can be turned into 1''s and vice versa"},{"id":"block-af68de5a-3e95-4ffa-894e-544db6d1ccc6","type":"section","value":"Spend 1 to heal 1 health"},{"id":"block-7542596f-05eb-452a-9f6d-80b113fd5193","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242389030_cbu20d3lmh6.png","imageSize":350},{"id":"block-c7b67679-e5e1-4775-a7d5-da094be078d9","type":"text","value":"The healing herbs are available right away. You can spend a 1 die on any turn to heal 1 health (erase a crossed out heart)."},{"id":"block-3b8423e2-3788-4fb1-9baf-afb40d5404b0","type":"text","value":"If a terrain ability (related to forests, fields, water or mountains) is unlocked, it will increase the range of numbers needed to move to those spaces. If you unlock one of these abilities, colour in the greyed out die at the top of the sheet to show that both of those numbers can now be used to move to those spaces."},{"id":"block-5ad33e95-fa7a-4f2a-9be0-aeece60ee88d","type":"section","value":"Key"},{"id":"block-7b409be6-c3be-4bf9-abae-bd9357f31f9e","type":"image","value":"https://fgbrxofiznkfhxdzjsjh.supabase.co/storage/v1/object/public/sherpa-images/d9d95c4e-5a12-4381-965c-4561982813a3/cff1d304-b866-458e-81fb-cd428ff3f503/1776242449781_d8zwm5wdafp.png","imageSize":370},{"id":"block-535b28ce-6aa4-435c-9caf-dadc76ce5553","type":"text","value":"The key is required to move to either castle tile and win the game."},{"id":"block-5424f91a-b420-4505-b1c2-b5c5e55f8bdf","type":"section","value":"Movement and Special Spaces"},{"id":"block-c7faf8c1-b828-4974-b8d0-f447b9458f75","type":"text","value":"The messenger can move to any of the four spaces in the top row of the map for the first move."},{"id":"block-86074a05-db23-457b-89e3-0ed675f5d5c1","type":"text","value":"Any die can be spent to move to a swamp (brown) space, but you lose 1 health."},{"id":"block-0389dbbd-ab68-4296-91fc-dd865a0d0616","type":"text","value":"If you move onto a space with a heart, erase a crossed out heart."}]'::jsonb,
